class ScraperMonitor {
  async checkScraperHealth(groupName) {
    const lastJob = await db.query(
      'SELECT status, completed_at FROM scrape_jobs WHERE group_name = $1 ORDER BY started_at DESC LIMIT 1',
      [groupName]
    );
    
    if (!lastJob.rows.length) {
      await this.sendAlert('No scraper jobs found for ' + groupName);
      return false;
    }
    
    const job = lastJob.rows[0];
    const hoursSinceLast = (Date.now() - job.completed_at) / (1000 * 60 * 60);
    
    if (job.status === 'failed') {
      await this.sendAlert('Scraper failed for ' + groupName + ': ' + job.error_message);
      return false;
    }
    
    if (hoursSinceLast > 48) {
      await this.sendAlert('Scraper stale for ' + groupName + ': Last run ' + hoursSinceLast + 'h ago');
      return false;
    }
    
    return true;
  }
  
  async sendAlert(message) {
    // Slack webhook
    await fetch('https://hooks.slack.com/services/...', {
      method: 'POST',
      body: JSON.stringify({
        text: '🚨 Scraper Alert: ' + message,
        channel: '#alerts'
      })
    });
    
    // Email
    await emailService.send({
      to: 'ops@woke.com',
      subject: 'Scraper Alert',
      body: message
    });
  }
}`})]}),o("div",{className:"flex flex-wrap gap-2",children:[i("span",{className:"bg-red-100 text-red-800 px-3 py-1 rounded-full text-sm",children:"Priority: Critical"}),i("span",{className:"bg-blue-100 text-blue-800 px-3 py-1 rounded-full text-sm",children:"Effort: 1 day"}),i("span",{className:"bg-green-100 text-green-800 px-3 py-1 rounded-full text-sm",children:"Impact: Data continuity"})]})]})]})]}),o("section",{children:[i("h2",{className:"text-2xl font-semibold text-gray-900 mb-4",children:"🤝 Customer Success Automations"}),o("div",{className:"space-y-4",children:[o("div",{className:"bg-white border-l-4 border-yellow-500 rounded-lg p-6",children:[i("h3",{className:"text-lg font-semibold text-yellow-800 mb-3",children:"⚠️ Missing: Automated Onboarding"}),i("p",{className:"text-gray-600 mb-4",children:"Manual setup for each brand takes 2-3 days. Impossible at scale."}),o("div",{className:"bg-gray-50 rounded p-4 mb-4",children:[i("h4",{className:"font-semibold mb-2",children:"Solution: Self-Service Onboarding"}),i("pre",{className:"text-sm text-gray-700 overflow-x-auto",children:`// Automated onboarding flow
